using System.Net.Http.Json;
using Microsoft.AspNetCore.Mvc.Testing;
using NBomber.CSharp;
using PlantDiseaseRecognition.WebApi.Api.Controllers;
using PlantDiseaseRecognition.WebApi.Engine.Rust.Models;

namespace PlantDiseaseRecognition.WebApi.LoadTesting;

public class LoadTests : IClassFixture<WebApplicationFactory<Program>>
{
	private readonly WebApplicationFactory<Program> _factory;

	public LoadTests(WebApplicationFactory<Program> factory)
	{
		_factory = factory;
	}

	[Fact]
	public async Task LoadTest_Inference_Gpu()
	{
		await using var factory = new TestWebApplicationFactory(DeviceType.Gpu);
		var client = factory.CreateClient();

		var scenario = Scenario.Create("inference_gpu", async context =>
		{
			var image = "";
			var request = new InferenceController.InferRequest(image);
			var content = JsonContent.Create(request);
			var result = await client.PostAsync("/api/v1/inference", content);
			return result.IsSuccessStatusCode
				? Response.Ok()
				: Response.Fail(
					statusCode: result.StatusCode.ToString()
				);
		})
			.WithWarmUpDuration(TimeSpan.FromSeconds(30))
			.WithLoadSimulations(
				Simulation.Inject(
					rate: 5,
					interval: TimeSpan.FromSeconds(1),
					during: TimeSpan.FromSeconds(60)
				)
			);

		var stats = NBomberRunner
			.RegisterScenarios(scenario)
			.WithReportFolder("load_test_results")
			.Run();
	}
}
